var b="url",c="出库日志_1.html",d="generationDate",e=new Date(1781592934543.51),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="c9216032ecfe477db558aa772bda17fb",u="type",v="Axure:Page",w="出库日志",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="91b40aa898934ee0b676bf5cab76c812",D="label",E="选项1",F="说明",G="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">数据来源</span></p><p><span>1.[手持终端&gt;&gt;辅料仓库：快速出库]</span></p><p><span>2.[手持终端&gt;&gt;辅料仓库：出库任务]</span></p>",H="2",I="e859551703f54b11b34b59ce3189c253",J="选项2",K="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">清单描述</span></p><p><span>将[辅料仓库系统&gt;&gt;出库日志：</span><span style=\"text-decoration:underline ;\">明细日志</span><span>]中的数据按</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&quot;关联出库单&quot;</span><span style=\"color:#D9001B;\">去重</span><span>后作为单位展示</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">字段描述</span></p><p><span>1.操作日期：去重数据中任意数据行'操作时间'的日期部分</span></p><p><span>2.操作人：去重数据中任意数据行的'操作人'</span></p><p><span>3.出库单号：跟随</span><span style=\"text-decoration:underline ;\">去重依据</span><span>对应的'关联出库单'</span></p><p><span>4.关联任务：去重数据中任意数据行的'关联出库任务'</span></p><p><span>5.类型：跟随'关联任务'于[辅料仓库系统&gt;&gt;出库任务]中对应的'类型'</span></p><p><span>6.出库种类：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">合计</span><span>该</span><span style=\"text-decoration:underline ;\">去重依据</span><span>对应数据行，按'SKU'</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">去重后的SKU数量</span></p><p><span>7.出库批次：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">合计</span><span>该</span><span style=\"text-decoration:underline ;\">去重依据</span><span>对应数据行，按'物料二维码'</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">去重后的物料二维码条数</span></p><p><span>8.出库数量：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">合计</span><span>该</span><span style=\"text-decoration:underline ;\">去重依据</span><span>对应数据行对应的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">'出库数量'</span><span>的数值</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">打印</span></p><p><span>1.预览展示</span></p><p><span>2.预览样式如图所示，点击可调用打印机</span></p>",L="3",M="ebca0ed1ba904bec8b6ff97b5e95a398",N="开始日期  ～  截止日期",O="<p><span>1.默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.开始时间：默认当月1号</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.截止时间：默认当日</span></p><p><span>2.格式：年/月/日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.选中视为'开始日期 00:00:00'至'截止日期 23:59:59'</span></p><p><span>3.快捷筛选</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.当月：本月1号~今日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.近1月：上月当日~今日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.近3月：三个月前当日~今日</span></p><p><span>4.开始日期与截止日期选择后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.立即针对“操作时间”列返回筛选结果</span></p>",P="4",Q="8f98c19331d24f0b8955acf4db8fb8ab",R="选择物料",S="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：选择物料</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;物料管理：物料明细]中 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">属性==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">辅料</span><span style=\"font-family:'Nunito Sans Bold Oblique', 'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;font-style:oblique;\"> </span><span>的'物料'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.下拉展示“物料编码”和“物料名称”2列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.右侧含“×‘的快捷清空按钮</span></p><p><span>3.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“物料名称”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“物料名称”列返回筛选结果</span></p>",T="5",U="ebe1f996cf5645e4b04e294e57bab9f0",V="物料颜色",W="<p><span>1.未选中提示字：物料颜色</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;物料管理：物料颜色]</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.展示颜色对应的“色号”、“颜色”、“颜色(中)”、“颜色(英)”、“供色单位”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.右侧含“×”的快捷清除按钮</span></p><p><span>3.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“颜色”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“颜色”列返回筛选结果</span></p>",X="6",Y="8d3b1b601df64e558d076190a2b22965",Z="(文本框)",ba="<p><span>1.提示字：</span><span style=\"color:#333333;\">二维码/出库单/出库任务</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.支持对“二维码”、“关联出库单”和“关联出库任务”列的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>2.点击【搜索】后返回查询结果</span></p>",bb="7",bc="f6dba1803d0d4f6089522ab9defd2914",bd="<p><span>1.提示字：</span><span style=\"color:#333333;\">用料单位</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.支持对“用料单位”的模糊查询</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>2.点击【搜索】后返回查询结果</span></p>",be="8",bf="a36a813aefbd40d89367e947aa9669c6",bg="<p><span>1.提示字：规格</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.支持对“规格”的模糊查询</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>2.点击【搜索】后返回查询结果</span></p>",bh="9",bi="e7458caa622f46f7acc91bb448da4131",bj="<p><span>1.默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.开始时间：默认当月1号</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.截止时间：默认当日</span></p><p><span>2.格式：年/月/日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.选中视为'开始日期 00:00:00'至'截止日期 23:59:59'</span></p><p><span>3.快捷筛选</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.当月：本月1号~今日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.近1月：上月当日~今日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.近3月：三个月前当日~今日</span></p><p><span>4.开始日期与截止日期选择后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.立即针对“操作日期”列返回筛选结果</span></p>",bk="10",bl="8744f9621ce84f3eae317abf56508ec1",bm="选择类型",bn="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：选择类型</span></p><p><span>2.可选性</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.生产</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.直接申请</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.自定义</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; d.</span><span style=\"color:#7F7F7F;\">其它可选项待规划…</span></p><p><span>3.右侧含“×‘的快捷清空按钮</span></p><p><span>4.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将对应选中项值返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“类型”列返回筛选结果</span></p>",bo="11",bp="19eff4916961435796e9222d1ec47064",bq="<p><span>1.提示字：</span><span style=\"color:#333333;\">出库单/出库任务/用料单位</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.支持对“出库单号”、“关联任务”、“用料单位”的模糊查询</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>2.点击【搜索】后返回查询结果</span></p>",b